13.     internal static class AppContextSwitchHelper
14.     {
15.         /// <summary>
16.         /// Determines if either an AppContext switch or its corresponding Environment Variable is set
17.         /// </summary>
18.         /// <param name="appContexSwitchName">Name of the AppContext switch.</param>
19.         /// <param name="environmentVariableName">Name of the Environment variable.</param>
20.         /// <returns>If the AppContext switch has been set, returns the value of the switch.
21.         /// If the AppContext switch has not been set, returns the value of the environment variable.
22.         /// False if neither is set.
23.         /// </returns>
24.         public static bool GetConfigValue(string appContexSwitchName, string environmentVariableName)
25.         {
26.             // First check for the AppContext switch, giving it priority over the environment variable.
27.             if (AppContext.TryGetSwitch(appContexSwitchName, out bool value))
28.             {
29.                 return value;
30.             }
31.             // AppContext switch wasn't used. Check the environment variable.
32.             string? envVar = Environment.GetEnvironmentVariable(environmentVariableName);
33.             if (envVar != null && (envVar.Equals("true", StringComparison.OrdinalIgnoreCase) || envVar.Equals("1")))
34.             {
35.                 return true;
36.             }
37. 
38.             // Default to false.
39.             return false;
40.         }
